const cfg = {};
for (const item of items) {
  const name  = (item.json.Name  ?? '').trim();
  const value = item.json.Value;
  if (name && value != null && value !== '') {
    cfg[name] = value;
  }
}
const required = ['Anthropic_ApiKey', 'prompt_canon_header', 'prompt_ideas_review'];
for (const key of required) {
  if (!cfg[key]) {
    throw new Error('[Build Config] Missing required key: ' + key + '. Add it to EnvironmentVariables table.');
  }
}
return [{ json: cfg }];

const ready = items.filter(function(i) {
  return String(i.json.status || '').trim().toUpperCase() === 'TOPIC_READY';
});

if (ready.length === 0) {
  throw new Error('No TOPIC_READY ideas found. Run ideas-to-sheet first.');
}

return ready.map(function(i) {
  return {
    json: {
      id:           i.json.id,
      topic:        String(i.json.topic        || '').trim(),
      angle:        String(i.json.angle        || '').trim(),
      niche:        String(i.json.niche        || '').trim(),
      status:       i.json.status,
      moment_type:  String(i.json.moment_type  || 'unknown').trim() || 'unknown',
      tension_type: String(i.json.tension_type || 'unknown').trim() || 'unknown'
    }
  };
});

const cfg = $('Code: Build Config').first().json;

const systemPrompt = (cfg.prompt_canon_header || '').trim();
const promptTemplate = cfg.prompt_ideas_review || '';

const canonAudience        = cfg.canon_audience         || 'Adults 25-45 interested in generational culture, humor, and nostalgia.';
const canonTone            = cfg.canon_tone             || 'Humorous, light, respectful. No political topics. No religion. No race-based humor.';
const canonNoGoTopics      = cfg.canon_no_go_topics     || 'Politics, religion, race, gender identity, mental health stigma, violence, sexuality.';
const canonBiasRules       = cfg.canon_bias_rules       || 'All three generations must be represented with equal respect and humor.';
const canonUniquenessRules = cfg.canon_uniqueness_rules || 'Each topic must target a DIFFERENT specific slang word, phrase, or cultural reference.';

return items.map(function(item) {
  const idea = item.json;
  const momentType  = String(idea.moment_type  || 'unknown').trim() || 'unknown';
  const tensionType = String(idea.tension_type || 'unknown').trim() || 'unknown';

  const userPrompt = promptTemplate
    .replace(/\{idea_id\}/g,              String(idea.id           || ''))
    .replace(/\{topic\}/g,               String(idea.topic        || ''))
    .replace(/\{angle\}/g,               String(idea.angle        || ''))
    .replace(/\{niche\}/g,               String(idea.niche        || ''))
    .replace(/\{moment_type\}/g,         momentType)
    .replace(/\{tension_type\}/g,        tensionType)
    .replace(/\{canon_audience\}/g,      canonAudience)
    .replace(/\{canon_tone\}/g,          canonTone)
    .replace(/\{canon_no_go_topics\}/g,  canonNoGoTopics)
    .replace(/\{canon_bias_rules\}/g,    canonBiasRules)
    .replace(/\{canon_uniqueness_rules\}/g, canonUniquenessRules);

  return {
    json: {
      idea_id:      idea.id,
      topic:        idea.topic,
      angle:        idea.angle,
      niche:        idea.niche,
      moment_type:  momentType,
      tension_type: tensionType,
      anthropic_payload: {
        model:      'claude-sonnet-4-5',
        max_tokens: 1024,
        system:     systemPrompt,
        messages:   [{ role: 'user', content: userPrompt }]
      }
    }
  };
});

const promptItems = $('Code: Build Review Prompts').all();
const results = [];

const growthDimensions = [
  { key: 'hook_strength',     label: 'hook_strength' },
  { key: 'contrast_strength', label: 'contrast_strength' },
  { key: 'relatability',      label: 'relatability' },
  { key: 'comment_potential', label: 'comment_potential' },
  { key: 'topic_clarity',     label: 'topic_clarity' }
];

const STRONG_MOMENT_TYPES  = ['misunderstanding', 'escalation', 'contradiction'];
const STRONG_TENSION_TYPES = ['generational', 'social', 'workplace', 'contradiction'];

function toBinaryScore(value) {
  const num = Number(value);
  if (!Number.isFinite(num)) { return 0; }
  return num >= 1 ? 1 : 0;
}

function toGrowthScore(value) {
  const num = Number(value);
  if (!Number.isFinite(num)) { return 0; }
  return Math.max(0, Math.min(10, Math.round(num)));
}

function parseAnthropicJson(httpItem) {
  const contentArr = Array.isArray(httpItem.content) ? httpItem.content : [];
  const rawText = contentArr
    .filter(function(block) { return block && block.type === 'text'; })
    .map(function(block) { return String(block.text || ''); })
    .join('\n')
    .trim() || String(httpItem.output_text || httpItem.completion || '');

  if (!rawText) { throw new Error('Empty text block in Anthropic response'); }

  const cleaned = rawText.trim()
    .replace(/^```[\w-]*[\r\n]+/, '')
    .replace(/[\r\n]+```$/, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (error) {
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/);
    if (!jsonMatch) { throw error; }
    return JSON.parse(jsonMatch[0]);
  }
}

function getWeakestGrowthDimension(scores) {
  return growthDimensions.reduce(function(weakest, dimension) {
    const value = scores[dimension.key];
    if (!weakest || value < weakest.value) {
      return { key: dimension.key, label: dimension.label, value: value };
    }
    return weakest;
  }, null);
}

function buildParseFailure(ideaId, topic, errorMessage) {
  return {
    idea_id: String(ideaId),
    topic: String(topic),
    gate_audience_fit: 0,
    gate_tone_compliance: 0,
    gate_uniqueness: 0,
    gate_bias_safety: 0,
    gate_factual_safety: 0,
    editorial_total_score: 0,
    total_score: 0,
    growth_fit_average: 0,
    hook_strength: 0,
    contrast_strength: 0,
    relatability: 0,
    comment_potential: 0,
    topic_clarity: 0,
    final_review_state: 'NEEDS_REWORK',
    verdict: 'NEEDS_REWORK',
    review_notes: 'Parse error: invalid Claude review response. Defaulted to NEEDS_REWORK and set all growth-fit scores to 0. Weakest growth-fit dimension: hook_strength (0/10).',
    parse_error: String(errorMessage || 'Unknown parse error')
  };
}

for (var i = 0; i < items.length; i++) {
  const httpItem   = items[i].json;
  const promptItem = (promptItems[i] || promptItems[0] || { json: {} }).json;
  const ideaId     = promptItem.idea_id || '';
  const topic      = promptItem.topic   || '';

  const momentType  = String(promptItem.moment_type  || 'unknown').trim().toLowerCase();
  const tensionType = String(promptItem.tension_type || 'unknown').trim().toLowerCase();

  const momentUnknown  = !momentType  || momentType  === 'unknown';
  const tensionUnknown = !tensionType || tensionType === 'unknown';
  const momentIsStrong  = STRONG_MOMENT_TYPES.includes(momentType);
  const tensionIsStrong = STRONG_TENSION_TYPES.includes(tensionType);

  let parsed;
  try {
    parsed = parseAnthropicJson(httpItem);
  } catch (error) {
    results.push({ json: buildParseFailure(ideaId, topic, error.message) });
    continue;
  }

  const gateAudienceFit   = toBinaryScore(parsed.gate_audience_fit);
  const gateToneCompliance = toBinaryScore(parsed.gate_tone_compliance);
  const gateUniqueness     = toBinaryScore(parsed.gate_uniqueness);
  const gateBiasSafety     = toBinaryScore(parsed.gate_bias_safety);
  const gateFactualSafety  = toBinaryScore(parsed.gate_factual_safety);

  const hookBoost     = (momentIsStrong && tensionIsStrong) ? 1 : 0;
  const contrastBoost = (momentIsStrong && tensionIsStrong) ? 1 : 0;

  const hookStrength     = Math.min(10, toGrowthScore(parsed.hook_strength)     + hookBoost);
  const contrastStrength = Math.min(10, toGrowthScore(parsed.contrast_strength) + contrastBoost);
  const relatability     = toGrowthScore(parsed.relatability);
  const commentPotential = toGrowthScore(parsed.comment_potential);
  const topicClarity     = toGrowthScore(parsed.topic_clarity);

  const editorialTotalScore = gateAudienceFit + gateToneCompliance + gateUniqueness + gateBiasSafety + gateFactualSafety;
  const growthFitAverage    = Number(((hookStrength + contrastStrength + relatability + commentPotential + topicClarity) / 5).toFixed(1));

  const momentTensionPass = !momentUnknown && !tensionUnknown;

  const finalReviewState = momentTensionPass && editorialTotalScore >= 4 && hookStrength >= 7 && contrastStrength >= 7 && growthFitAverage >= 7.5
    ? 'REVIEW_APPROVED'
    : 'NEEDS_REWORK';

  const weakestGrowth = getWeakestGrowthDimension({
    hook_strength: hookStrength, contrast_strength: contrastStrength,
    relatability: relatability, comment_potential: commentPotential, topic_clarity: topicClarity
  });

  const rawReason = String(parsed.main_reason || parsed.review_notes || '').replace(/\s+/g, ' ').trim().replace(/[.]+$/, '');

  let reason = rawReason;
  if (!reason) {
    if (momentUnknown) {
      reason = 'moment_type is unknown — idea lacks interaction mechanics';
    } else if (tensionUnknown) {
      reason = 'tension_type is unknown — idea lacks tension signal';
    } else if (editorialTotalScore < 4) {
      reason = 'editorial_total_score ' + editorialTotalScore + '/5 is below 4';
    } else if (hookStrength < 7) {
      reason = 'hook_strength ' + hookStrength + '/10 is below 7';
    } else if (contrastStrength < 7) {
      reason = 'contrast_strength ' + contrastStrength + '/10 is below 7';
    } else if (growthFitAverage < 7.5) {
      reason = 'growth_fit_average ' + growthFitAverage + '/10 is below 7.5';
    } else {
      reason = 'all editorial and growth-fit thresholds are met';
    }
  }

  const momentLabel  = momentIsStrong  ? 'strong (' + momentType  + ')'  : momentUnknown  ? 'missing/unknown' : 'weak (' + momentType  + ')';
  const tensionLabel = tensionIsStrong ? 'strong (' + tensionType + ')' : tensionUnknown ? 'missing/unknown' : 'weak (' + tensionType + ')';
  const mechanicsSuffix = ' Moment quality: ' + momentLabel + '. Tension strength: ' + tensionLabel + '.';

  const reviewNotes = finalReviewState === 'REVIEW_APPROVED'
    ? 'Approved: ' + reason + '.' + mechanicsSuffix
    : 'Rejected: ' + reason + '. Weakest growth-fit dimension: ' + weakestGrowth.label + ' (' + weakestGrowth.value + '/10).' + mechanicsSuffix;

  results.push({
    json: {
      idea_id:               String(parsed.idea_id || ideaId),
      topic:                 String(parsed.topic   || topic),
      final_review_state:    finalReviewState,
      verdict:               finalReviewState,
      total_score:           editorialTotalScore,
      editorial_total_score: editorialTotalScore,
      growth_fit_average:    growthFitAverage,
      review_notes:          reviewNotes,
      gate_audience_fit:     gateAudienceFit,
      gate_tone_compliance:  gateToneCompliance,
      gate_uniqueness:       gateUniqueness,
      gate_bias_safety:      gateBiasSafety,
      gate_factual_safety:   gateFactualSafety,
      hook_strength:         hookStrength,
      contrast_strength:     contrastStrength,
      relatability:          relatability,
      comment_potential:     commentPotential,
      topic_clarity:         topicClarity
    }
  });
}

return results;

function getReviewState(item) {
  return String(item.json.final_review_state || item.json.verdict || item.json.status || '').trim().toUpperCase();
}

const total_reviewed = items.length;
const approved = items.filter(function(item) { return getReviewState(item) === 'REVIEW_APPROVED'; }).length;
const needs_rework = items.filter(function(item) { return getReviewState(item) === 'NEEDS_REWORK'; }).length;
const approval_rate = total_reviewed > 0
  ? Math.round((approved / total_reviewed) * 100) + '%'
  : '0%';

return [{
  json: {
    status: 'REVIEW_COMPLETE',
    total_reviewed: total_reviewed,
    approved: approved,
    needs_rework: needs_rework,
    approval_rate: approval_rate,
    review_model: 'claude-sonnet-4-5',
    timestamp: new Date().toISOString()
  }
}];
